local function dump(name, content)
    print("\n========== DUMP (" .. name .. ") ==========\n")
    print(content)
    print("\n==========================================\n")
end

-- Hook load / loadstring
local old_load = load
local old_loadstring = loadstring

load = function(code, ...)
    if type(code) == "string" then
        dump("load", code)
    end
    return old_load(code, ...)
end

loadstring = function(code, ...)
    if type(code) == "string" then
        dump("loadstring", code)
    end
    return old_loadstring(code, ...)
end

-- Hook tostring (kadang dipakai buat decode)
local old_tostring = tostring
tostring = function(v)
    local res = old_tostring(v)
    return res
end

-- Hook table.concat (sering dipakai gabung payload)
local old_concat = table.concat
table.concat = function(t, sep)
    local result = old_concat(t, sep)
    if #result > 50 then
        dump("table.concat", result)
    end
    return result
end

-- Hook string.char (decode byte → string)
local old_char = string.char
string.char = function(...)
    local result = old_char(...)
    if #result > 5 then
        dump("string.char", result)
    end
    return result
end

